/**
 * @summary Add an update/observation to a field
 */
export const getCreateFieldUpdateUrl = (id: number) => {
  return `/api/fields/${id}/updates`;
};

export const createFieldUpdate = async (
  id: number,
  createFieldUpdateBody: CreateFieldUpdateBody,
  options?: RequestInit,
): Promise<FieldUpdate> => {
  return customFetch<FieldUpdate>(getCreateFieldUpdateUrl(id), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(createFieldUpdateBody),
  });
};

export const getCreateFieldUpdateMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createFieldUpdate>>,
    TError,
    { id: number; data: BodyType<CreateFieldUpdateBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createFieldUpdate>>,
  TError,
  { id: number; data: BodyType<CreateFieldUpdateBody> },
  TContext
> => {
  const mutationKey = ["createFieldUpdate"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createFieldUpdate>>,
    { id: number; data: BodyType<CreateFieldUpdateBody> }
  > = (props) => {
    const { id, data } = props ?? {};

    return createFieldUpdate(id, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateFieldUpdateMutationResult = NonNullable<
  Awaited<ReturnType<typeof createFieldUpdate>>
>;
export type CreateFieldUpdateMutationBody = BodyType<CreateFieldUpdateBody>;
export type CreateFieldUpdateMutationError = ErrorType<ErrorResponse>;

/**
 * @summary Add an update/observation to a field
 */
export const useCreateFieldUpdate = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createFieldUpdate>>,
    TError,
    { id: number; data: BodyType<CreateFieldUpdateBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof createFieldUpdate>>,
  TError,
  { id: number; data: BodyType<CreateFieldUpdateBody> },
  TContext
> => {
  return useMutation(getCreateFieldUpdateMutationOptions(options));
};

